# Python 3.11+
import threading
import time
from abc import ABC, abstractmethod
from collections.abc import Iterator
from contextlib import contextmanager


class Clock(ABC):
    @abstractmethod
    def now(self) -> float: ...

    @abstractmethod
    def guard(self) -> Iterator[None]:
        """Hold the lock that guards the queue AND backs wait()/wake() (ctx mgr)."""

    @abstractmethod
    def wait(self, timeout: float | None) -> None:
        """Park up to `timeout`s; None = until woken. MUST be called holding
        guard(); atomically releases that lock while parked (no lost wakeup)."""

    @abstractmethod
    def wake(self) -> None:
        """Wake every thread parked in wait()."""


class SystemClock(Clock):
    def __init__(self) -> None:
        # RLock so the scheduler's reentrant _guard can re-enter; Condition.wait
        # still releases the FULL recursion level and restores it on wake.
        self._cond = threading.Condition(threading.RLock())

    def now(self) -> float:
        return time.time()

    @contextmanager
    def guard(self) -> Iterator[None]:
        with self._cond:
            yield

    def wait(self, timeout: float | None) -> None:
        # WHY: caller holds guard() (this lock). wait() releases it while parked
        #      and re-takes it on wake. Because the heap predicate was checked
        #      under this SAME lock with no release before parking, a wake() from
        #      submit/cancel can never slip into a gap — there is no gap.
        self._cond.wait(timeout)

    def wake(self) -> None:
        with self._cond:
            self._cond.notify_all()


class FakeClock(Clock):
    def __init__(self, start: float = 0.0) -> None:
        self._t = start
        self._cond = threading.Condition(threading.RLock())

    def now(self) -> float:
        with self._cond:
            return self._t

    @contextmanager
    def guard(self) -> Iterator[None]:
        with self._cond:
            yield

    def wait(self, timeout: float | None) -> None:
        self._cond.wait(timeout)  # caller holds guard(); park, releasing it

    def wake(self) -> None:
        with self._cond:
            self._cond.notify_all()

    def advance(self, dt: float) -> None:
        # WHY: bump the fake time then wake parked workers so they re-evaluate
        #      "what's due now?" — this single call fast-forwards a test.
        with self._cond:
            self._t += dt
            self._cond.notify_all()

    def set(self, t: float) -> None:
        with self._cond:
            self._t = t
            self._cond.notify_all()
